class UpdateUserMutation(graphene.Mutation):

    class Arguments:
        user = UserInput()

    updated_user = graphene.Field('User', description='The updated user')

    @classmethod
    def mutate(cls, root, info, **args):

        user = args['user']
        email = user['email']
        username = user['username']
        bio = user['bio']
        role = user['role']
        is_admin = user['is_admin']
        credits = user['credits']
        subscription_tier = user['subscription_tier']

        existing_user = next(
            (u for u in User if u.email == email and u.username == username), None)

        existing_user.email = email or existing_user.email
        existing_user.bio = bio or existing_user.bio
        existing_user.role = role or existing_user.role
        existing_user.is_admin = is_admin or existing_user.is_admin
        existing_user.credits = credits or existing_user.credits
        existing_user.subscription_tier = subscription_tier or existing_user.subscription_tier

        return cls(
            updated_user=existing_user)


